document.addEventListener("click",o=>{const r=o.target.closest('[data-bs-toggle="collapse"]');if(r){const e=r.getAttribute("data-bs-target"),t=e&&document.querySelector(e);if(t){t.classList.toggle("show"),r.setAttribute("aria-expanded",t.classList.contains("show")),o.preventDefault();return}}const c=o.target.closest('[data-bs-toggle="dropdown"]');if(c){const e=c.parentElement,t=e&&e.querySelector(".menu__dropdown");t&&(document.querySelectorAll(".menu__dropdown.show").forEach(s=>{s!==t&&!t.contains(s)&&!s.contains(t)&&s.classList.remove("show")}),t.classList.toggle("show"),o.preventDefault());return}!o.target.closest(".menu__dropdown")&&!o.target.closest(".menu__item")&&document.querySelectorAll(".menu__dropdown.show").forEach(e=>e.classList.remove("show"))});
